func TestParseModelListAcceptsDataAndModelsEnvelopes(t *testing.T) {
	dataModels, err := parseModelList(json.RawMessage(`{"data":[{"id":"grok-a"}]}`), "data")
	if err != nil {
		t.Fatalf("data envelope: %v", err)
	}
	if len(dataModels) != 1 || dataModels[0].ID != "grok-a" {
		t.Fatalf("unexpected data models: %#v", dataModels)
	}

	familyModels, err := parseModelList(json.RawMessage(`{"models":[{"id":"grok-b"}]}`), "models")
	if err != nil {
		t.Fatalf("models envelope: %v", err)
	}
	if len(familyModels) != 1 || familyModels[0].ID != "grok-b" {
		t.Fatalf("unexpected family models: %#v", familyModels)
	}
}

func TestRankModelsForTaskPrefersReasoningModels(t *testing.T) {
	models := []xaiModelInfo{
		{ID: "grok-non-reasoning", InputModalities: []string{"text"}, OutputModalities: []string{"text"}},
		{ID: "grok-reasoning", InputModalities: []string{"text"}, OutputModalities: []string{"text"}, Aliases: []string{"grok-reasoning-latest"}},
	}
	for i := range models {
		models[i].Capabilities, models[i].CapabilityConfidence = deriveCapabilities(models[i])
	}

	recs := rankModelsForTask(models, "reasoning", "balanced", 2)
	if len(recs) != 1 {
		t.Fatalf("expected one reasoning recommendation, got %#v", recs)
	}
	if recs[0].Model != "grok-reasoning" {
		t.Fatalf("expected reasoning model first, got %#v", recs[0])
	}
}

